function show(id, skipHash){
document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
const el = document.getElementById(id);
if(!el) return;
el.classList.add('active');
window.scrollTo(0,0);
updateBC();
if(id === 's-ai'){ setTimeout(aiLaadScherm, 50); }
if(!skipHash){
try{
const newHash = '#' + id;
if(window.location.hash !== newHash){
history.pushState({screenId: id}, '', newHash);
}
}catch(e){}
}
}
window.addEventListener('popstate', function(e){
const screenId = (e.state && e.state.screenId) || (window.location.hash ? window.location.hash.slice(1) : 's-lj');
if(screenId === 's-er'){
if(window._erTimerInterval){ clearInterval(window._erTimerInterval); }
window._erKlaar = true;
var pbw = document.getElementById('er-progress-wrap');
if(pbw) pbw.remove();
var overlay = document.getElementById('er-stop-overlay');
if(overlay) overlay.style.display = 'none';
show('s-md', true);
return;
}
show(screenId, true);
});
function laadExterneData(url, onSuccess, onError) {
var laadEl = document.getElementById('laad-status');
if (laadEl) { laadEl.textContent = '⏳ Data wordt geladen...'; laadEl.style.display = 'block'; }
fetch(url)
.then(function(r) {
if (!r.ok) throw new Error('HTTP ' + r.status + ' bij ' + url);
return r.json();
})
.then(function(data) {
if (laadEl) laadEl.style.display = 'none';
onSuccess(data);
})
.catch(function(err) {
if (laadEl) { laadEl.textContent = '❌ Data kon niet worden geladen. Herlaad de pagina.'; }
console.error('[vlaconomie] Kon ' + url + ' niet laden:', err);
if (typeof onError === 'function') onError(err);
});
}
function telBezoek(){
const el = document.getElementById('bt-getal');
const wrap = document.getElementById('bezoek-teller-el');
if(!el || !wrap) return;
fetch('https://api.counterapi.dev/v1/vlaconomie/bezoeken-2024/up')
.then(r => r.ok ? r.json() : Promise.reject())
.then(d => {
const waarde = d && (d.count ?? d.value);
if(waarde != null){
wrap.style.display = '';
el.textContent = Number(waarde).toLocaleString('nl-NL');
} else { wrap.style.display = 'none'; }
})
.catch(() => { wrap.style.display = ''; el.textContent = '1.000+'; });
}
