function initActualiteitWidget(){
var w = document.getElementById('actualiteit-widget');
if(!w) return;
var dag = new Date().getDate() + new Date().getMonth() * 31;
var item = ACTUALITEIT_DATA[dag % ACTUALITEIT_DATA.length];
document.getElementById('act-tekst').textContent = item.t;
document.getElementById('act-datum').textContent = new Date().toLocaleDateString('nl-NL',{weekday:'long',day:'numeric',month:'long'});
if(item.v){
document.getElementById('act-vraag-tekst').textContent = item.v;
document.getElementById('act-vraag').style.display = '';
document.getElementById('act-vraag').style.cursor = 'pointer';
document.getElementById('act-vraag').title = 'Klik voor het antwoord';
document.getElementById('act-vraag').onclick = function(){
if(!this.dataset.open){
this.innerHTML += '<div style="margin-top:.4rem;background:rgba(255,255,255,.15);border-radius:6px;padding:.4rem .6rem;font-size:.8rem">💡 '+ddEsc(item.d)+'</div>';
this.dataset.open = '1';
}
};
}
w.style.display = '';
}
setTimeout(initActualiteitWidget, 300);
