function go(modus){
if(modus==='th') toonTH();
else if(modus==='sam') toonSam();
else if(modus==='rekenen') show('s-rekenen');
else if(modus==='escaperooms') show('s-escaperooms');
else if(modus==='beg') toonBeg();
else if(modus==='downloads'){ const t=document.getElementById('dl-onderwerp-naam'); if(t&&huidigeData&&huidigeData.t)t.textContent='Downloads voor: '+huidigeData.t; show('s-downloads'); }
else if(modus==='fc'){fcI=0;toonFC();}
else if(modus==='kop') bouwKop();
else if(modus==='inv'){ivI=0;ivSc=0;toonInv();}
else if(modus==='vr'){vrI=0;vrSc=0;toonVr();}
else if(modus==='rk'){rkI=0;rkSc=0;toonRk();}
else if(modus==='wz') bouwWZ();
else if(modus==='fm') toonFm();
else if(modus==='er1') toonEr(1);
else if(modus==='er2') toonEr(2);
else if(modus==='er3') toonEr(3);
else if(modus==='er4') toonEr(4);
else if(modus==='er5') toonEr(5);
else if(modus==='er6') toonEr(6);
else if(modus==='bt') toonBT();
else if(modus==='fn') toonFN();
else if(modus==='rh') toonRH();
else if(modus==='po') toonPO();
else if(modus==='po') toonPO();
else if(modus==='rk2') show('s-rk2');
else if(modus==='ehbo') toonEHBO();
}
function toonDownloads(){
var subEl = document.getElementById('dl-onderwerp-naam');
var topicNaam = (getTopic && getTopic().t) ? getTopic().t : null;
if(subEl) subEl.textContent = topicNaam ? 'Downloads voor: ' + topicNaam : 'Werkbladen en materialen';
var owMap = {
'schaarste': ['schaarste'],
'vraag':     ['vraag'],
'arbeid':    ['arbeidsmarkt'],
'bedrijf':   ['productie'],
'overheid':  ['overheid'],
'milieu':    ['milieu'],
'behoeften': ['schaarste']
};
var actief = OW ? (owMap[OW] || null) : null;
document.querySelectorAll('#s-downloads [data-topic]').forEach(function(el){
var topics = (el.getAttribute('data-topic') || '').split(',').map(function(s){ return s.trim(); });
if(!actief){
el.style.display = '';
} else {
var match = topics.some(function(t){ return actief.indexOf(t) !== -1; });
el.style.display = match ? '' : 'none';
}
});
var banner = document.getElementById('dl-meer-banner');
if(banner) banner.style.display = '';
show('s-downloads');
}
