function btToggleCel(el, rijId){
var bron = BT_DATA[btIdx];
var idx2 = btGeselecteerd.indexOf(rijId);
if(idx2 > -1){
btGeselecteerd.splice(idx2,1);
el.classList.remove('geselecteerd');
el.setAttribute('aria-pressed','false');
} else {
btGeselecteerd.push(rijId);
el.classList.add('geselecteerd');
el.setAttribute('aria-pressed','true');
}
var tel = document.getElementById('bt-tel');
if(tel){
tel.textContent = btGeselecteerd.length+'/'+bron.aantalVereist+' geselecteerd';
tel.setAttribute('aria-live','polite');
}
if(btGeselecteerd.length === bron.aantalVereist){
btControleerSelectie();
}
}
function btLeegSelectie(){
btGeselecteerd = [];
var bron = BT_DATA[btIdx];
document.querySelectorAll('.bt-cel').forEach(function(el){
el.classList.remove('geselecteerd','fout-geselecteerd','gemist');
el.setAttribute('aria-pressed','false');
});
var tel = document.getElementById('bt-tel');
if(tel) tel.textContent = '0/'+bron.aantalVereist+' geselecteerd';
document.getElementById('bt-fase2').style.display='none';
}
function btControleerSelectie(){
var bron = BT_DATA[btIdx];
var relevanteIds = bron.rijen.filter(function(r){ return r.relevant; }).map(function(r){ return r.id; });
var alleJuist = relevanteIds.every(function(id){ return btGeselecteerd.indexOf(id)>-1; })
&& btGeselecteerd.every(function(id){ return relevanteIds.indexOf(id)>-1; });
if(alleJuist){
document.querySelectorAll('.bt-cel.geselecteerd').forEach(function(el){
el.style.background='#1a7a4a';
el.style.color='#fff';
});
document.getElementById('bt-fase2').style.display='block';
document.getElementById('bt-fase2').scrollIntoView({behavior:'smooth',block:'nearest'});
} else {
btGeselecteerd.forEach(function(id){
var el = document.querySelector('[data-rij="'+id+'"]');
if(el && relevanteIds.indexOf(id)===-1) el.classList.add('fout-geselecteerd');
});
relevanteIds.forEach(function(id){
if(btGeselecteerd.indexOf(id)===-1){
var el = document.querySelector('[data-rij="'+id+'"]');
if(el) el.classList.add('gemist');
}
});
setTimeout(function(){
document.querySelectorAll('.bt-cel.fout-geselecteerd,.bt-cel.gemist').forEach(function(el){
el.classList.remove('fout-geselecteerd','gemist');
});
}, 1800);
}
}
function btControleer(){
var bron = BT_DATA[btIdx];
var inp = document.getElementById('bt-invoer');
var val = parseFloat(inp.value.replace(',','.'));
var fb = document.getElementById('bt-feedback');
var volgende = document.getElementById('bt-volgende-btn');
if(isNaN(val)){
fb.className='bt-feedback fout';
fb.textContent='Vul een getal in.';
return;
}
if(Math.abs(val - bron.antwoord) <= bron.marge){
fb.className='bt-feedback goed';
fb.innerHTML='✅ Goed gedaan! '+bron.uitleg;
btVoltooide.push(btIdx);
var dots = document.querySelectorAll('.bt-stap-dot');
if(dots[btIdx]) dots[btIdx].className='bt-stap-dot klaar';
if(btIdx < BT_DATA.length-1){
volgende.style.display='inline-flex';
} else {
document.getElementById('bt-opnieuw-btn').style.display='inline-flex';
}
inp.disabled = true;
} else {
fb.className='bt-feedback fout';
fb.innerHTML='❌ Niet helemaal. Controleer je selectie en berekening. <br><small>'+bron.hint+'</small>';
}
}
function btToonHint(){
var hint = document.getElementById('bt-hint');
if(hint) hint.style.display = hint.style.display==='block'?'none':'block';
}
function btVolgende(){
btIdx++;
btGeselecteerd=[];
btFaseStap=1;
btBouwVraag();
var cont = document.getElementById('bt-vraag-container');
if(cont) cont.scrollIntoView({behavior:'smooth',block:'start'});
}
function btToonEinde(){
var wrap = document.getElementById('bt-vraag-container');
if(!wrap) return;
var score = btVoltooide.length;
var tot = BT_DATA.length;
var pct = Math.round(score/tot*100);
var emoji = pct>=80 ? '🏆' : pct>=50 ? '👍' : '📚';
wrap.innerHTML = '<div style="text-align:center;padding:2rem 1rem">'
+'<div style="font-size:3rem">'+emoji+'</div>'
+'<h2 style="margin:.5rem 0">'+score+' van '+tot+' bronnen correct</h2>'
+'<p style="color:var(--muted)">Je hebt alle bronnen doorlopen. Ga terug en oefen verder of druk op Opnieuw.</p>'
+'</div>';
document.getElementById('bt-opnieuw-btn').style.display='inline-flex';
document.getElementById('bt-volgende-btn').style.display='none';
}
function gaTerug(s){if(window.speechSynthesis)window.speechSynthesis.cancel();if(typeof _resetLuister==='function')_resetLuister(_luisterBtn,null,null);show(s);}
