function getData(){
var base=C[OW]||{};
var nivKey=getNivKey();
var thObj=TH[OW]||null;
if(thObj){
var thData=thObj[nivKey]||thObj['bb']||thObj['k']||null;
if(thData){
if(!base.vr && thData.vr) base=Object.assign({},base,{vr:thData.vr});
if(!base.beg && thData.beg) base=Object.assign({},base,{beg:thData.beg});
}
}
if(NV==='basis'||NV==='kader'){
var prefix=NV==='basis'?'bb':'k';
var out=Object.assign({},base);
if(base[prefix+'_er1']) out.er1=base[prefix+'_er1'];
if(base[prefix+'_er2']) out.er2=base[prefix+'_er2'];
return out;
}
return base;
}
function updateBC(){
const bc = document.getElementById('breadcrumb');
const cur = document.querySelector('.screen.active')?.id || '';
const geenBC = ['s-lj','s-nv','s-over','s-dash','s-doc','s-ai','s-sim','s-pr'];
if(!LJ || geenBC.includes(cur)){
bc.className = 'bc-verborgen';
bc.style.display = 'none';
return;
}
const schermLabels = {
's-ow':'Onderwerpen','s-md':'Oefenen','s-sam':'Samenvatting',
's-beg':'Begrippen','s-fc':'Flashcards','s-kop':'Koppelen',
's-inv':'Invulopdracht','s-vr':'Oefenvragen','s-downloads':'Downloads','s-begrippen':'Begrippen','s-rekenen':'Rekenen','s-rk':'Rekensommen','s-escaperooms':'Escaperooms','s-zdw':'Zoek de Denkfout',
's-wz':'Woordzoeker','s-fm':'Formules','s-er':'Escaperoom',
's-fn':'Functioneel rekenen','s-po':'Praktijkopdracht',
's-ex':'Oefenexamens','s-exw':'Examen','s-exr':'Resultaat','s-ehbo':'Examen-EHBO','s-bt':'Bron-Trainer'
};
const sep = '<span class="bc-sep">›</span>';
const item = (label, fn) =>
`<span class="bc-item" onclick="${fn}">${label}</span>`;
const huidig = (label) =>
`<span class="bc-huidig">${label}</span>`;
let delen = [];
delen.push(item('🏠 Home', "goHome()"));
if(LJ){
const nvLabel = NV ? (NVS[LJ]?.find(n=>n.id===NV)?.l || NV) : null;
if(cur === 's-ow'){
delen.push(huidig(`LJ ${LJ} — ${nvLabel||''}`));
} else {
delen.push(item(`LJ ${LJ}${nvLabel?' — '+nvLabel:''}`, "show('s-ow')"));
}
}
if(OW && cur !== 's-ow'){
const owLabel = getTopic().t || OW;
if(cur === 's-md'){
delen.push(huidig(owLabel));
} else {
delen.push(item(owLabel, "show('s-md')"));
}
}
const huidigLabel = schermLabels[cur];
if(huidigLabel && cur !== 's-ow' && cur !== 's-md'){
delen.push(huidig(huidigLabel));
}
bc.innerHTML = delen.join(sep);
bc.className = 'bc-zichtbaar';
bc.style.display = 'flex';
}
