el.innerHTML=(d.beg||[]).map((b,i)=>`
<button type="button" class="bi" onclick="this.classList.toggle('open')" aria-expanded="false" aria-label="${b.t} — klik om definitie te tonen">
<div class="trm"><span class="tog">▸</span>${b.t}</div>
<div class="def">${b.d}</div>
</button>`).join('');
