function toonFC(){
const d=getData();const allBeg=d.beg||[];
if(!allBeg.length){show('s-fc');return;}
const nk=getNivKey();
const maxBeg={bb:4,k:5,tl:6,h:8,v:99}[nk]||6;
const beg=allBeg.slice(0,Math.min(maxBeg,allBeg.length));
window._fcBeg=beg;
if(fcI>=beg.length) fcI=0;
const b=beg[fcI];
document.getElementById('fc-t').textContent=b.t;
document.getElementById('fc-d').textContent=b.d;
document.getElementById('fc-cnt').textContent=`${fcI+1} / ${beg.length}` + (getNivKey()==='bb'?' (niveau: basis)':getNivKey()==='k'?' (niveau: kader)':'');
document.getElementById('fc-pb').style.width=`${(fcI+1)/beg.length*100}%`;
document.getElementById('fcard').classList.remove('flip');
show('s-fc');
}
function flipCard(){document.getElementById('fcard').classList.toggle('flip');}
function fcN(){const d=getData();fcI=Math.min(fcI+1,(d.beg||[]).length-1);toonFC();}
function fcV(){fcI=Math.max(fcI-1,0);toonFC();}
function bouwKop(){
const d=getData();
const allesBeg=(d.beg||[]);
if(!allesBeg.length){
show('s-kop');
document.getElementById('k-res').innerHTML='<p>Geen begrippen beschikbaar.</p>';
return;
}
const beg=[...allesBeg].sort(()=>Math.random()-.5).slice(0,6);
window._kopBeg=beg;
kGoed=0;
window._kopSel=null;
const defVolgorde=[...beg].sort(()=>Math.random()-.5);
const kl=document.getElementById('kl');
const kr=document.getElementById('kr');
kl.innerHTML=beg.map((b,i)=>
`<div class="ki" data-bi="${i}" data-kant="term" onclick="selKop(this)">${b.t}</div>`
).join('');
kr.innerHTML=defVolgorde.map((b)=>{
const bi=beg.findIndex(x=>x.t===b.t);
return `<div class="ki def" data-bi="${bi}" data-kant="def" onclick="selKop(this)">${b.d}</div>`;
}).join('');
document.getElementById('k-res').innerHTML='';
updKsc();
show('s-kop');
}
function updKsc(){
const tot=window._kopBeg?window._kopBeg.length:0;
document.getElementById('ksc').textContent=`${kGoed} / ${tot} gekoppeld`;
}
function selKop(el){
if(el.classList.contains('ok')) return;
const vorige=window._kopSel;
if(!vorige){
el.classList.add('sel');
window._kopSel=el;
return;
}
if(vorige===el){
el.classList.remove('sel');
window._kopSel=null;
return;
}
if(vorige.dataset.kant===el.dataset.kant){
vorige.classList.remove('sel');
el.classList.add('sel');
window._kopSel=el;
return;
}
const biVorige=parseInt(vorige.dataset.bi);
const biNieuw =parseInt(el.dataset.bi);
if(biVorige===biNieuw){
[vorige,el].forEach(e=>{e.classList.remove('sel');e.classList.add('ok');});
window._kopSel=null;
kGoed++;
updKsc();
if(kGoed===window._kopBeg.length){
markeerGedaan('kop');
document.getElementById('k-res').innerHTML=`
<div class="sbox">
<div class="big">🎉</div>
<p>Alle ${kGoed} begrippen goed gekoppeld!</p>
<div class="na-oefening-btns">
<button class="btn" onclick="bouwKop()">🔄 Nieuw spel</button>
<button class="btn sec" onclick="go('vr')">✏️ Oefenvragen</button>
<button class="btn sec" onclick="gaTerug('s-md')">← Terug</button>
</div>
</div>`;
}
} else {
[vorige,el].forEach(e=>{
e.classList.add('no');
setTimeout(()=>{e.classList.remove('no','sel');},700);
});
window._kopSel=null;
}
}
