function checkInvul(){
const d=getData();const item=(d.iv||[])[ivI];if(!item)return;
const inp=document.getElementById('iv-inp');if(!inp)return;
const val=inp.value.trim().toLowerCase();
const ok=val===item.a.toLowerCase()||val.includes(item.a.toLowerCase())||item.a.toLowerCase().includes(val)&&val.length>=3;
const fb=document.getElementById('iv-fb');
if(ok){inp.classList.add('ok');fb.className='fb goed show';fb.textContent=`✓ Goed! ${item.u}`;ivSc++;}
else{inp.classList.add('no');fb.className='fb fout show';fb.textContent=`✗ Het antwoord is: "${item.a}". ${item.u}`;}
inp.disabled=true;
document.getElementById('iv-chk').style.display='none';
document.getElementById('iv-nxt').style.display='';
}
function nextInvul(){ivI++;toonInv();}
