function _ec(n){ try{return btoa(String(n));}catch(e){return String(n);} }
function _dc(s){
if(typeof s==='number') return s;
try{ return parseInt(atob(s),10); }catch(e){ return parseInt(s,10)||0; }
}
function _patchVraag(v){
if(v && typeof v.c==='string') v.c=_dc(v.c);
return v;
}
