function bouwWZ(){
const d=getData();
const beg=(d.beg||[]);
if(!beg.length){show('s-wz');document.getElementById('wz-gr').innerHTML='<p>Geen begrippen beschikbaar.</p>';return;}
const kandidaten=beg.map(b=>{
const volledig=b.t.toLowerCase().replace(/[\s\-]/g,'').replace(/[^a-z]/g,'');
if(volledig.length>=4&&volledig.length<=11) return {woord:volledig,label:b.t};
const eerste=b.t.split(/[\s\-]/)[0].toLowerCase().replace(/[^a-z]/g,'');
if(eerste.length>=4&&eerste.length<=11) return {woord:eerste,label:b.t};
return null;
}).filter(Boolean);
const gezien=new Set();
const woordObjs=kandidaten.filter(k=>{
if(gezien.has(k.woord)) return false;
gezien.add(k.woord); return true;
}).slice(0,6);
if(!woordObjs.length){
show('s-wz');
document.getElementById('wz-gr').innerHTML='<p>Geen geschikte woorden gevonden voor de woordzoeker.</p>';
return;
}
const woorden=woordObjs.map(k=>k.woord);
const maxLen=Math.max(...woorden.map(w=>w.length));
const SIZE=Math.min(12, Math.max(maxLen+3, 10));
let grid=Array.from({length:SIZE},()=>Array(SIZE).fill(''));
wzPlaced=[];wzFound=[];wzStart=null;
window._wzHighlight=[];
const dirs=[[0,1],[1,0],[0,-1],[-1,0]];
woordObjs.forEach(obj=>{
const w=obj.woord;
let placed=false;let tries=0;
while(!placed&&tries<300){
tries++;
const dir=dirs[Math.floor(Math.random()*dirs.length)];
const r=Math.floor(Math.random()*SIZE);
const c=Math.floor(Math.random()*SIZE);
let ok=true;const cells=[];
for(let i=0;i<w.length;i++){
const nr=r+dir[0]*i,nc=c+dir[1]*i;
if(nr<0||nr>=SIZE||nc<0||nc>=SIZE||(grid[nr][nc]!==''&&grid[nr][nc]!==w[i])){ok=false;break;}
cells.push([nr,nc]);
}
if(ok){
cells.forEach(([nr,nc],i)=>grid[nr][nc]=w[i]);
wzPlaced.push({w,label:obj.label,cells});
placed=true;
}
}
});
const abc='abcdefghijklmnopqrstuvwxyz';
for(let r=0;r<SIZE;r++)
for(let c=0;c<SIZE;c++)
if(!grid[r][c])grid[r][c]=abc[Math.floor(Math.random()*26)];
const gr=document.getElementById('wz-gr');
gr.innerHTML='';
const beschikbaar=Math.min(window.innerWidth-48, 480);
const celGrootte=Math.max(24, Math.floor(beschikbaar/SIZE));
gr.style.gridTemplateColumns=`repeat(${SIZE},${celGrootte}px)`;
gr.style.fontSize=`${Math.max(11,celGrootte-10)}px`;
for(let r=0;r<SIZE;r++){
for(let c=0;c<SIZE;c++){
const cel=document.createElement('div');
cel.className='wzc';
cel.textContent=grid[r][c].toUpperCase();
cel.dataset.r=r;cel.dataset.c=c;
cel.addEventListener('mousedown',e=>{e.preventDefault();wzStartSel(r,c);});
cel.addEventListener('mouseover',()=>wzHoverSel(r,c));
cel.addEventListener('mouseup',()=>wzEindSel());
cel.addEventListener('touchstart',e=>{e.preventDefault();wzStartSel(r,c);},{passive:false});
cel.addEventListener('touchmove',e=>{
e.preventDefault();
const t=e.touches[0];
const el=document.elementFromPoint(t.clientX,t.clientY);
if(el&&el.dataset.r) wzHoverSel(parseInt(el.dataset.r),parseInt(el.dataset.c));
},{passive:false});
cel.addEventListener('touchend',()=>wzEindSel());
gr.appendChild(cel);
}
}
const wl=document.getElementById('wz-wl');
wl.innerHTML=wzPlaced.map(p=>`<span class="wzw" id="wzw-${p.w}">${p.label.toUpperCase()}</span>`).join('');
document.getElementById('wz-res').innerHTML='';
document.getElementById('wz-instructie').textContent='Veeg over de letters van een woord';
show('s-wz');
}
let _wzDragging=false;
let _wzStartR=null,_wzStartC=null;
let _wzCurR=null,_wzCurC=null;
function wzStartSel(r,c){
_wzDragging=true;
_wzStartR=r;_wzStartC=c;
_wzCurR=r;_wzCurC=c;
wzTekenHighlight();
}
function wzHoverSel(r,c){
if(!_wzDragging)return;
_wzCurR=r;_wzCurC=c;
wzTekenHighlight();
}
function wzEindSel(){
if(!_wzDragging)return;
_wzDragging=false;
wzControleer(_wzStartR,_wzStartC,_wzCurR,_wzCurC);
document.querySelectorAll('.wzc.sel').forEach(e=>e.classList.remove('sel'));
}
function wzGetCellen(r0,c0,r1,c1){
const dr=r1-r0, dc=c1-c0;
if(dr!==0&&dc!==0) return []; // diagonaal = niet geldig
if(dr===0&&dc===0) return [[r0,c0]];
const len=Math.max(Math.abs(dr),Math.abs(dc))+1;
const sr=Math.sign(dr),sc=Math.sign(dc);
return Array.from({length:len},(_,i)=>[r0+sr*i,c0+sc*i]);
}
function wzTekenHighlight(){
document.querySelectorAll('.wzc.sel').forEach(e=>e.classList.remove('sel'));
const cellen=wzGetCellen(_wzStartR,_wzStartC,_wzCurR,_wzCurC);
cellen.forEach(([r,c])=>{
const el=document.querySelector(`.wzc[data-r="${r}"][data-c="${c}"]`);
if(el&&!el.classList.contains('fnd')) el.classList.add('sel');
});
}
function wzControleer(r0,c0,r1,c1){
const cellen=wzGetCellen(r0,c0,r1,c1);
if(cellen.length<2) return;
const woord=cellen.map(([r,c])=>{
const el=document.querySelector(`.wzc[data-r="${r}"][data-c="${c}"]`);
return el?el.textContent.toLowerCase():'';
}).join('');
const achterstevoren=woord.split('').reverse().join('');
const match=wzPlaced.find(p=>(p.w===woord||p.w===achterstevoren)&&!wzFound.includes(p.w));
if(match){
wzFound.push(match.w);
match.cells.forEach(([r,c])=>{
const el=document.querySelector(`.wzc[data-r="${r}"][data-c="${c}"]`);
if(el){el.classList.remove('sel');el.classList.add('fnd');}
});
const wspan=document.getElementById(`wzw-${match.w}`);
if(wspan) wspan.classList.add('fnd');
if(wzFound.length===wzPlaced.length){
markeerGedaan('wz');
document.getElementById('wz-res').innerHTML=`
<div class="sbox">
<div class="big">🎉</div>
<p>Alle woorden gevonden!</p>
<div class="na-oefening-btns">
<button class="btn" onclick="bouwWZ()">🔄 Nieuw spel</button>
<button class="btn sec" onclick="go('vr')">✏️ Oefenvragen</button>
<button class="btn sec" onclick="gaTerug('s-md')">← Terug</button>
</div>
</div>`;
}
}
}
