function getKamerCode(kamerData){
if(!kamerData||!kamerData.st)return'0000';
var totaal=kamerData.st.length;
var som=0;
for(var i=0;i<totaal-1;i++){
var s=kamerData.st[i];
var val=s.num!==undefined?s.num:(s.codeVal!==undefined?s.codeVal:i+1);
som+=val;
}
return String(som).padStart(4,'0').slice(-4);
}
