function erBerekenDynamischeCode(er){
if(er.code){window._erCijferCode=er.code;return;}
var ant=window._erAntwoorden||[];
var totaal=er.st.length;
var nums=[];
for(var i=0;i<totaal-1;i++){
var s=er.st[i];
if(ant[i]!==undefined){
var val=s.num!==undefined?s.num:(s.codeVal!==undefined?s.codeVal:(ant[i]+1));
nums.push(val);
}
}
if(nums.length===(totaal-1)){
var som=nums.reduce(function(a,b){return a+b;},0);
window._erCijferCode=String(som).padStart(4,'0').slice(-4);
window._erNumeriekeSom=som;
} else {
window._erCijferCode=getKamerCode(er);
}
}
