+'<div style="margin-top:.4rem;padding:.4rem .7rem;background:rgba(255,200,0,.07);border-left:3px solid #ffcc44;font-size:.85rem;color:#ffdd88;font-family:var(--er-font)">&#128161; <strong>Uitleg:</strong> '+uitlegTekst+'</div>'
+extraHint
+(window._erLevens>0?'':'<div style="color:#ff6666;margin-top:.3rem;font-size:.82rem">&#9888; Geen levens meer...</div>')
+'<button id="er-opnieuw-btn" disabled style="margin-top:.6rem;padding:.35rem .9rem;background:#223322;border:1px solid #446644;color:#778877;border-radius:4px;font-family:var(--er-font);font-size:.78rem;cursor:not-allowed">&#9203; Lees de uitleg... (<span id="er-countdown">3</span>s)</button>';
