function triggerHackerAttack(){
try{
var lgKey='vla_glitch_ts';
var laatste=parseInt(localStorage.getItem(lgKey)||'0',10);
var nu=Date.now();
if(nu - laatste < 864e5){ return; }
localStorage.setItem(lgKey, String(nu));
}catch(e){}
var overlay=document.getElementById('er-glitch-overlay');
if(!overlay)return;
overlay.style.display='block';
var frames=[
'background:rgba(255,0,0,0.08)',
'background:rgba(0,255,136,0.12)',
'background:transparent',
'background:rgba(255,0,255,0.06)',
'background:transparent',
'background:rgba(0,0,255,0.07)',
'background:rgba(255,0,0,0.1)',
'background:transparent',
];
var i=0;
var glitchInterval=setInterval(function(){
overlay.style.cssText='position:fixed;top:0;left:0;right:0;bottom:0;z-index:9999;pointer-events:none;'+frames[i%frames.length];
if(i%2===0){
document.body.style.transform='translateX('+(Math.random()*6-3)+'px)';
document.body.style.filter='hue-rotate('+(Math.random()*30)+'deg)';
} else {
document.body.style.transform='';
document.body.style.filter='';
}
i++;
if(i>16){
clearInterval(glitchInterval);
overlay.style.display='none';
document.body.style.transform='';
document.body.style.filter='';
}
},80);
}
