function genereerKlascode(score, totaal, onderwerp, niveau){
var ts=Math.floor(Date.now()/60000);
var raw=onderwerp+'|'+niveau+'|'+score+'|'+totaal+'|'+ts;
var hash=0;
for(var i=0;i<raw.length;i++) hash=((hash<<5)-hash+raw.charCodeAt(i))|0;
var code=niveau.substring(0,2).toUpperCase()+'-'+
onderwerp.substring(0,3).toUpperCase()+'-'+
score+'v'+totaal+'-'+
(Math.abs(hash)%9000+1000);
return code;
}
function toonKlascodePopup(score, totaal, onderwerp, niveau){
var code=genereerKlascode(score,totaal,onderwerp,niveau);
var bestaand=document.getElementById('klascode-popup');
if(bestaand) bestaand.remove();
var popup=document.createElement('div');
popup.id='klascode-popup';
popup.style.cssText='position:fixed;bottom:80px;left:50%;transform:translateX(-50%);background:#1a1a2e;color:#fff;border-radius:16px;padding:1.2rem 1.5rem;z-index:9999;box-shadow:0 8px 32px rgba(0,0,0,.4);text-align:center;max-width:320px;width:calc(100% - 2rem)';
popup.innerHTML='<div style="font-family:Lexend,sans-serif;font-weight:800;font-size:.85rem;margin-bottom:.4rem;color:#a0e4b0">\uD83D\uDCCB Jouw klascode</div>'+
'<div style="font-family:monospace;font-size:1.4rem;font-weight:900;letter-spacing:.12em;color:#ffd700;margin:.5rem 0">'+code+'</div>'+
'<div style="font-size:.75rem;color:#aaa;margin-bottom:.8rem">Geef deze code aan je docent als bewijs van je score</div>'+
'<div style="display:flex;gap:.5rem;justify-content:center">'+
'<button id="kc-copy" style="background:#1a7a4a;color:#fff;border:none;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;font-weight:700;cursor:pointer;font-family:Lexend,sans-serif">&#x1F4CB; Kopieer</button>'+
'<button onclick="document.getElementById(\'klascode-popup\').remove()" style="background:#333;color:#aaa;border:none;border-radius:8px;padding:.4rem .9rem;font-size:.78rem;cursor:pointer;font-family:Lexend,sans-serif">Sluiten</button>'+
'</div>';
document.body.appendChild(popup);
var cb=document.getElementById('kc-copy');
if(cb) cb.addEventListener('click',function(){
if(navigator.clipboard){navigator.clipboard.writeText(code).then(function(){cb.textContent='\u2705 Gekopieerd!';setTimeout(function(){cb.textContent='\uD83D\uDCCB Kopieer';},2000);}).catch(function(){alert('Code: '+code);});}
else{alert('Code: '+code);}
});
setTimeout(function(){var p=document.getElementById('klascode-popup');if(p)p.remove();},30000);
}
