function schaarsteSimUpdate(){
const sl=document.getElementById('sl-slaap');
const sb=document.getElementById('sl-baan');
if(!sl||!sb)return;
const slaap=+sl.value;
const baan=+sb.value;
const leer=Math.max(0,10-slaap-baan);
const vslaap=document.getElementById('val-slaap');
const vbaan=document.getElementById('val-baan');
const vleer=document.getElementById('val-leer');
if(vslaap)vslaap.textContent=slaap;
if(vbaan)vbaan.textContent=baan;
if(vleer)vleer.textContent=leer;
const loon=baan*12;
const basisLeer=4;
const puntVerlies=Math.max(0,(basisLeer-leer)*0.3).toFixed(1);
const oppKosten=(loon+(parseFloat(puntVerlies)*20)).toFixed(0);
const resultEl=document.getElementById('sim-result');
const warnEl=document.getElementById('sim-warn');
if(resultEl){
resultEl.innerHTML='<strong>\u{1F4B0} Verdiend met bijbaantje:</strong> \u20AC'+loon+'<br>'
+'<strong>\u{1F4C9} Toetspuntverlies (tov '+basisLeer+'u leren):</strong> \u2212'+puntVerlies+' punt<br>'
+'<strong>\u2696\uFE0F Opportuniteitskosten totaal:</strong> \u20AC'+oppKosten+' (loon + puntverlies \xe0 \u20AC20/punt)<br>'
+'<strong>\u{1F634} Slaaptekort?</strong> '+(slaap<7?'\u26A0\uFE0F Ja \u2014 onder 7 uur schaadt concentratie':'\u2705 Voldoende');
}
if(warnEl){
if(slaap<6){warnEl.style.display='block';warnEl.textContent='\u26A0\uFE0F Suboptimale allocatie: slaaptekort verlaagt je arbeidsproductiviteit morgen m\xe9\xe9r dan het bijbaantje vandaag oplevert.';}
else if(baan>4&&leer<2){warnEl.style.display='block';warnEl.textContent='\u{1F4CA} Hoge korte-termijn opbrengst, maar humankapitaal (opleiding) wordt onderbenut. Op lange termijn zijn de opportuniteitskosten van minder leren groter dan het bijbaantje-loon.';}
else{warnEl.style.display='none';}
}
}
document.addEventListener('DOMContentLoaded',function(){schaarsteSimUpdate();});
function getNivKey(){
if(!NV)return 'bb';
if(NV==='basis')return 'bb';
if(NV==='kader')return 'k';
if(NV==='tl')return 'tl';
if(NV==='tl-havo')return 'h';
return 'v';
}
