function zoekInTheorie(query){
const wisBtn = document.getElementById('zoek-wis-btn');
const resultDiv = document.getElementById('zoek-resultaten');
query = query.trim();
wisBtn.classList.toggle('actief', query.length > 0);
if(query.length < 2){
resultDiv.classList.remove('zichtbaar');
return;
}
const hits = [];
const qLower = query.toLowerCase();
const re = new RegExp('('+query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+')', 'gi');
Object.keys(C).forEach(owKey => {
const owData = C[owKey];
const niveaus = ['bb','k','tl','h','v','hv'];
niveaus.forEach(niv => {
const blokken = owData[niv];
if(!Array.isArray(blokken)) return;
blokken.forEach(blok => {
const tekst = (blok.t||'') + ' ' + ((blok.c||'').replace(/<[^>]+>/g,' '));
if(tekst.toLowerCase().includes(qLower)){
const idx = tekst.toLowerCase().indexOf(qLower);
const start = Math.max(0, idx - 60);
const end = Math.min(tekst.length, idx + 120);
const snippet = (start>0?'…':'') + tekst.slice(start,end).replace(re,'<mark>$1</mark>') + (end<tekst.length?'…':'');
let topicLabel = owKey;
Object.keys(TP).forEach(lj => {
Object.keys(TP[lj]).forEach(nv => {
(TP[lj][nv]||[]).forEach(t => { if(t.id===owKey) topicLabel = t.t; });
});
});
const nivLabels = {bb:'vmbo basis',k:'vmbo kader',tl:'vmbo TL',h:'havo',v:'vwo',hv:'havo/vwo'};
hits.push({owKey, niv, blokTitel: blok.t||'', snippet, topicLabel, nivLabel: nivLabels[niv]||niv});
}
});
});
if(owData.sam){
const tekst = owData.sam.replace(/<[^>]+>/g,' ');
if(tekst.toLowerCase().includes(qLower)){
const idx = tekst.toLowerCase().indexOf(qLower);
const start = Math.max(0, idx - 60);
const end = Math.min(tekst.length, idx + 120);
const snippet = (start>0?'…':'') + tekst.slice(start,end).replace(re,'<mark>$1</mark>') + (end<tekst.length?'…':'');
let topicLabel = owKey;
Object.keys(TP).forEach(lj => {
Object.keys(TP[lj]).forEach(nv => {
(TP[lj][nv]||[]).forEach(t => { if(t.id===owKey) topicLabel = t.t; });
});
});
hits.push({owKey, niv:'sam', blokTitel:'Samenvatting', snippet, topicLabel, nivLabel:'Samenvatting'});
}
}
});
const uniek = [];
const gezien = new Set();
hits.forEach(h => {
const key = h.owKey+'_'+h.niv+'_'+h.blokTitel.slice(0,20);
if(!gezien.has(key)){ gezien.add(key); uniek.push(h); }
});
if(uniek.length === 0){
const begripsHits=[];
Object.keys(C).forEach(owKey=>{
const owData=C[owKey];
const niveaus=['bb','k','tl','h','v','hv'];
niveaus.forEach(niv=>{
const beg=owData.beg||[];
if(!Array.isArray(beg))return;
beg.forEach(b=>{
if(!b||!b.b)return;
if(b.b.toLowerCase().includes(qLower)||(b.d&&b.d.toLowerCase().includes(qLower))){
begripsHits.push({begrip:b.b,def:b.d||'',owKey});
}
});
});
});
const bUniek=[];const bGezien=new Set();
begripsHits.forEach(bh=>{if(!bGezien.has(bh.begrip)){bGezien.add(bh.begrip);bUniek.push(bh);}});
if(bUniek.length>0){
const re2=new RegExp('('+query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+')','gi');
resultDiv.innerHTML=bUniek.slice(0,5).map(bh=>`<div class="zoek-begrip-hit"><div class="zbh-label">💡 Begrip gevonden</div><div class="zbh-begrip">${bh.begrip.replace(re2,'<mark>$1</mark>')}</div><div class="zbh-def">${(bh.def||'Geen definitie beschikbaar').replace(re2,'<mark>$1</mark>')}</div></div>`).join('');
} else {
resultDiv.innerHTML = `<div class="zoek-geen">Geen theorie gevonden voor "<strong>${query}</strong>"</div>`;
}
} else {
resultDiv.innerHTML = uniek.slice(0,8).map(h =>
`<div class="zoek-hit" role="option" onclick="zoekNavigeerNaar('${h.owKey}','${h.niv}')" tabindex="0" onkeydown="if(event.key==='Enter')zoekNavigeerNaar('${h.owKey}','${h.niv}')">
<div class="zoek-hit-titel">${h.blokTitel || h.topicLabel}</div>
<div class="zoek-hit-context">${h.snippet}</div>
<div class="zoek-hit-pad">📚 ${h.topicLabel} · ${h.nivLabel}</div>
</div>`
).join('') + (uniek.length > 8 ? `<div class="zoek-geen" style="font-size:.75rem;color:#aaa">${uniek.length-8} meer resultaten — typ specifieker om te verfijnen</div>` : '');
}
resultDiv.classList.add('zichtbaar');
}
function zoekNavigeerNaar(owKey, niv){
document.getElementById('zoek-balk-wrap').classList.remove('zichtbaar');
document.getElementById('zoek-resultaten').classList.remove('zichtbaar');
let gevondenLj = null, gevondenNv = null;
outer: for(const lj of Object.keys(TP)){
for(const nv of Object.keys(TP[lj])){
if((TP[lj][nv]||[]).some(t=>t.id===owKey)){
gevondenLj = lj; gevondenNv = nv; break outer;
}
}
}
if(gevondenLj) LJ = gevondenLj;
if(gevondenNv) NV = gevondenNv;
OW = owKey;
if(niv === 'sam'){
go('sam');
} else {
go('th');
}
toonMelding(`Naar theorie: ${owKey} (${niv})`);
}
function berekenKoopkracht(){
const oudEl   = document.getElementById('kk-oud');
const nieuwEl = document.getElementById('kk-nieuw');
const infEl   = document.getElementById('kk-inf');
const stEl    = document.getElementById('kk-stappen');
const utEl    = document.getElementById('kk-uitkomst');
if(!oudEl || !nieuwEl || !infEl || !stEl || !utEl) return;
const oud  = parseFloat(oudEl.value)  || 0;
const nieuw= parseFloat(nieuwEl.value)|| 0;
const inf  = parseFloat(infEl.value)  || 0;
if(oud <= 0){
stEl.innerHTML = '<em style="color:#999">Vul een geldig oud loon in.</em>';
utEl.innerHTML = ''; return;
}
const nomStijging = (nieuw - oud) / oud * 100;
const reeel       = nomStijging - inf;
const positief    = reeel >= 0;
stEl.innerHTML =
'<strong>Stap 1 &mdash; Nominale loonstijging:</strong><br>' +
'&nbsp;&nbsp;(&euro;' + nieuw.toFixed(0) + ' &minus; &euro;' + oud.toFixed(0) +
') &divide; &euro;' + oud.toFixed(0) + ' &times; 100%' +
' = <strong>' + nomStijging.toFixed(1) + '%</strong><br><br>' +
'<strong>Stap 2 &mdash; Trek de inflatie eraf:</strong><br>' +
'&nbsp;&nbsp;' + nomStijging.toFixed(1) + '% &minus; ' + inf.toFixed(1) + '% inflatie' +
' = <strong>' + reeel.toFixed(1) + '% reële koopkrachtverandering</strong>';
utEl.style.cssText =
'margin-top:.7rem;border-radius:10px;padding:.8rem 1rem;text-align:center;font-weight:700;font-size:1rem;' +
(positief
? 'background:#d4f7e4;border:2px solid #2ecc71;color:#1a7a4a;'
: 'background:#fde8d8;border:2px solid #e74c3c;color:#c0392b;');
utEl.innerHTML =
(positief ? '&#x1F4C8; Koopkracht stijgt' : '&#x1F4C9; Koopkracht daalt') +
' met <strong>' + Math.abs(reeel).toFixed(1) + '%</strong>' +
(positief
? ' &mdash; je kunt <em>meer</em> kopen dan vorig jaar! &#x2705;'
: ' &mdash; je kunt <em>minder</em> kopen, ook al stijgt je loon. &#x26A0;&#xFE0F;');
}
