const LT_MODUS_CFG = [
{ modus:'th',  emoji:'📚', label:'Theorie',        sub:t=>`Lees de uitleg over ${t.toLowerCase()}` },
{ modus:'fc',  emoji:'🃏', label:'Flashcards',     sub:t=>`Oefen de begrippen van ${t.toLowerCase()} met flashcards` },
{ modus:'vr',  emoji:'✏️', label:'Oefenvragen',    sub:t=>`Beantwoord de meerkeuzevragen over ${t.toLowerCase()}` },
{ modus:'rk',  emoji:'🔢', label:'Rekensommen',    sub:t=>`Maak de rekensommen bij ${t.toLowerCase()}` },
{ modus:'er1', emoji:'🔐', label:'Escaperoom',     sub:t=>`Los de escaperoom op over ${t.toLowerCase()}` },
];
const LT_EXTRA_STAPPEN = [
{ id:'lt-rekentrainer', emoji:'⏱️', titel:'Rekentrainer',    sub:'Oefen de Big Five rekenvaardigheden',  special:'rekentrainer' },
{ id:'lt-rekenhulp',    emoji:'🆘', titel:'Rekenhulp',       sub:'Bekijk stappenplannen bij rekenproblemen', special:'rekenhulp' },
];
const LT_NIV_LABELS = {
basis:'vmbo basis', kader:'vmbo kader', tl:'vmbo tl',
'tl-havo':'tl / havo', 'havo-vwo':'havo / vwo'
};
function ltBouwStappen(){
if(!LJ || !NV) return [];
const topics = (TP[LJ]||{})[NV] || [];
const nivLabel = LT_NIV_LABELS[NV] || NV;
const stappen = [];
topics.forEach(topic => {
const tNaam = topic.t;
LT_MODUS_CFG.forEach(cfg => {
if(cfg.modus === 'rk' && ['milieu','loopbaan','schaarste'].includes(topic.id)) return;
if(cfg.modus === 'er1' && NV === 'havo-vwo') return;
stappen.push({
id: `${cfg.modus}-${topic.id}`,
emoji: cfg.emoji,
titel: `${cfg.label}: ${tNaam}`,
sub: cfg.sub(tNaam),
niv: nivLabel,
ow: topic.id,
modus: cfg.modus,
});
});
});
LT_EXTRA_STAPPEN.forEach(s => stappen.push({...s, niv: nivLabel}));
return stappen;
}
function ltGetVoortgang(){
try{
const raw = localStorage.getItem('lt_voortgang_v2');
return raw ? JSON.parse(raw) : {};
} catch(e){ return {}; }
}
function ltSlaVoortgangOp(stapId, gedaan){
try{
const v = ltGetVoortgang();
v[stapId] = gedaan;
localStorage.setItem('lt_voortgang_v2', JSON.stringify(v));
renderLeertraject();
} catch(e){ console.warn('localStorage niet beschikbaar'); }
}
function ltAllesWissen(){
if(!confirm('Weet je zeker dat je de leertraject-voortgang wilt wissen?')) return;
try{ localStorage.removeItem('lt_voortgang_v2'); } catch(e){}
renderLeertraject();
}
function toonLeertraject(){
if(!LJ || !NV){
alert('Kies eerst je leerjaar en niveau, dan zie je jouw persoonlijke leertraject.');
show('s-lj');
return;
}
show('s-leertraject');
renderLeertraject();
}
function renderLeertraject(){
const container = document.getElementById('lt-stappen-container');
if(!container) return;
const stappen = ltBouwStappen();
const v = ltGetVoortgang();
const gedaanCount = stappen.filter(s => v[s.id]).length;
const pct = stappen.length ? Math.round((gedaanCount / stappen.length) * 100) : 0;
const nivLabel = (LT_NIV_LABELS[NV] || NV || '').toUpperCase();
const pctEl = document.getElementById('lt-pct-getal');
if(pctEl) pctEl.textContent = pct + '%';
const txtEl = document.getElementById('lt-voortgang-tekst');
if(txtEl){
if(!LJ || !NV)
txtEl.textContent = 'Kies je leerjaar en niveau voor een persoonlijk leerpad';
else if(pct === 100)
txtEl.textContent = `🎉 Alles afgerond voor ${nivLabel}! Goed bezig!`;
else if(pct > 60)
txtEl.textContent = `${gedaanCount} van ${stappen.length} stappen klaar — bijna!`;
else if(pct > 0)
txtEl.textContent = `${gedaanCount} van ${stappen.length} stappen klaar — ga zo door!`;
else
txtEl.textContent = `${stappen.length} stappen voor ${nivLabel} — begin bij stap 1`;
}
const subEl = document.querySelector('#s-leertraject .ssub');
if(subEl && LJ && NV)
subEl.textContent = `Leerjaar ${LJ} · ${nivLabel} — doorloop de stappen van theorie naar oefening`;
if(!stappen.length){
container.innerHTML = '<p style="color:var(--muted);text-align:center;padding:2rem">Kies een leerjaar en niveau om je leertraject te zien.</p>';
return;
}
const groepen = {};
const volgorde = [];
stappen.forEach(stap => {
const key = stap.ow || stap.id;
if(!groepen[key]){ groepen[key] = []; volgorde.push(key); }
groepen[key].push(stap);
});
let html = '';
let stapNr = 0;
volgorde.forEach(key => {
const stappenInGroep = groepen[key];
const eersteStap = stappenInGroep[0];
const groepGedaan = stappenInGroep.filter(s => v[s.id]).length;
const groepTotaal = stappenInGroep.length;
const groepPct = Math.round(groepGedaan / groepTotaal * 100);
const groepKleur = groepPct === 100 ? '#27ae60' : groepPct > 0 ? '#f59e0b' : '#dde';
const groepLabel = eersteStap.special
? (eersteStap.emoji + ' ' + eersteStap.titel)
: `📖 ${eersteStap.titel.split(': ')[1] || key}`;
html += `<div class="lt-groep" style="margin-bottom:1.2rem">
<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.5rem">
<div style="font-family:'Lexend',sans-serif;font-weight:800;font-size:.88rem;color:var(--fg)">${groepLabel}</div>
<div style="margin-left:auto;font-size:.75rem;color:${groepKleur};font-weight:700">${groepGedaan}/${groepTotaal}</div>
<div style="width:60px;height:6px;background:#eee;border-radius:3px;overflow:hidden">
<div style="width:${groepPct}%;height:100%;background:${groepKleur};border-radius:3px;transition:width .4s"></div>
</div>
</div>`;
stappenInGroep.forEach((stap, gi) => {
stapNr++;
const isGedaan = !!v[stap.id];
const isSpecial = !!stap.special;
const vorigeGedaan = gi === 0 || !!v[stappenInGroep[gi-1].id];
const bereikbaar = isGedaan || vorigeGedaan;
const bgKleur = isGedaan ? '#f0fdf4' : bereikbaar ? 'var(--bg2)' : 'var(--bg2)';
const borderKleur = isGedaan ? '#27ae60' : bereikbaar ? 'var(--border)' : '#eee';
const opacity = bereikbaar ? '1' : '0.55';
html += `<div class="lt-stap" style="
display:flex;align-items:center;gap:.7rem;
background:${bgKleur};border:1.5px solid ${borderKleur};
border-radius:10px;padding:.7rem .9rem;margin-bottom:.4rem;
cursor:${bereikbaar ? 'pointer' : 'default'};
opacity:${opacity};
transition:box-shadow .15s,transform .15s"
onclick="${bereikbaar ? `ltStapKlik('${stap.id}')` : ''}"
onmouseover="${bereikbaar ? "this.style.boxShadow='0 3px 12px rgba(0,0,0,.1)';this.style.transform='translateY(-1px)'" : ''}"
onmouseout="${bereikbaar ? "this.style.boxShadow='';this.style.transform=''" : ''}">
<div style="
width:28px;height:28px;border-radius:50%;flex-shrink:0;
display:flex;align-items:center;justify-content:center;
background:${isGedaan ? '#27ae60' : bereikbaar ? 'var(--white)' : '#f0f0f0'};
border:2px solid ${isGedaan ? '#27ae60' : bereikbaar ? '#ccc' : '#eee'};
font-size:${isGedaan ? '.85rem' : '.75rem'};
font-weight:700;color:${isGedaan ? '#fff' : '#aaa'}">
${isGedaan ? '✓' : stapNr}
</div>
<div style="flex:1;min-width:0">
<div style="font-size:.87rem;font-weight:700;color:var(--fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">
${stap.emoji} ${stap.titel}
</div>
<div style="font-size:.76rem;color:var(--muted);margin-top:.1rem">${stap.sub}</div>
</div>
<button
onclick="event.stopPropagation(); ltSlaVoortgangOp('${stap.id}', ${!isGedaan})"
style="
padding:.3rem .65rem;border-radius:8px;font-size:.72rem;font-weight:700;
font-family:'Lexend',sans-serif;cursor:pointer;flex-shrink:0;white-space:nowrap;
border:1.5px solid ${isGedaan ? '#27ae60' : '#dde'};
background:${isGedaan ? '#27ae60' : 'transparent'};
color:${isGedaan ? '#fff' : '#aaa'}"
title="${isGedaan ? 'Klik om te ontkoppelen' : 'Markeer als gedaan'}">
${isGedaan ? '✓ Klaar' : 'Vink af'}
</button>
</div>`;
});
html += '</div>';
});
container.innerHTML = html;
}
function ltStapKlik(stapId){
const stappen = ltBouwStappen();
const stap = stappen.find(s => s.id === stapId);
if(!stap) return;
if(stap.special === 'rekentrainer'){ show('s-rekentrainer'); return; }
if(stap.special === 'rekenhulp')  { go('rh'); return; }
if(stap.special === 'ehbo')       { if(typeof toonEHBO === 'function') toonEHBO(); return; }
if(stap.special === 'ex')         { go('ex'); return; }
if(stap.ow && stap.modus){
OW = stap.ow;
const mdTitle = document.getElementById('md-title');
if(mdTitle) mdTitle.textContent = stap.titel.split(': ')[1] || stap.ow;
const v = ltGetVoortgang();
if(!v[stap.id]){
setTimeout(() => {
ltSlaVoortgangOp(stap.id, true);
}, 3000);
}
go(stap.modus);
}
}
var VLA_SCORES_KEY = 'vla_quiz_scores_v2';
var VLA_FC_KEY = 'vla_flashcard_done';
var VLA_CASUS_KEY = 'vla_casus_done';
function laadPersistenteScores(){
try {
var opgeslagen = JSON.parse(localStorage.getItem(VLA_SCORES_KEY)||'[]');
window.ltScores = Array.isArray(opgeslagen) ? opgeslagen.slice(-200) : [];
} catch(e){ window.ltScores = []; }
}
function slaScoreOp(module, goed, totaal, naam){
try {
var entry = {
id: module,
module: naam||module,
goed: goed,
totaal: totaal,
pct: totaal>0?Math.round((goed/totaal)*100):0,
tijdstip: new Date().toLocaleTimeString('nl-NL',{hour:'2-digit',minute:'2-digit'}),
datum: new Date().toLocaleDateString('nl-NL')
};
window.ltScores.push(entry);
localStorage.setItem(VLA_SCORES_KEY, JSON.stringify(window.ltScores.slice(-200)));
} catch(e){}
}
laadPersistenteScores();
window.ltScores = window.ltScores || [];
function registreerScore(module, goed, totaal, naam){
slaScoreOp(module, goed, totaal, naam);
}
var EQ_KEY = 'vla_eigen_vragen_v1';
function eigenVragenLaad(){
try { return JSON.parse(localStorage.getItem(EQ_KEY)||'[]'); } catch(e){ return []; }
}
function eigenVragenSla(arr){
try { localStorage.setItem(EQ_KEY, JSON.stringify(arr)); } catch(e){}
}
function eigenVraagOpslaan(){
var type = document.getElementById('eq-type').value;
var vraag = (document.getElementById('eq-vraag').value||'').trim();
var uitleg = (document.getElementById('eq-uitleg').value||'').trim();
var niveau = parseInt(document.getElementById('eq-niveau').value||'2');
var foutEl = document.getElementById('eq-fout');
foutEl.style.display = 'none';
if(!vraag){ foutEl.textContent = 'Vul een vraag in.'; foutEl.style.display = ''; return; }
var entry = { id: 'eq_'+Date.now(), typ: type, q: vraag, u: uitleg, d: niveau };
if(type === 'mc'){
var opts = ['eq-o0','eq-o1','eq-o2','eq-o3'].map(id => (document.getElementById(id).value||'').trim());
if(opts.filter(Boolean).length < 2){ foutEl.textContent = 'Vul minstens 2 antwoordopties in.'; foutEl.style.display = ''; return; }
var correctRadio = document.querySelector('input[name="eq-correct"]:checked');
if(!correctRadio){ foutEl.textContent = 'Selecteer het juiste antwoord.'; foutEl.style.display = ''; return; }
entry.o = opts;
entry.c = parseInt(correctRadio.value);
}
var arr = eigenVragenLaad();
arr.push(entry);
eigenVragenSla(arr);
eigenVraagFormLeeg();
eigenVragenToonLijst();
toonMelding('Vraag opgeslagen ✓');
}
function eigenVraagFormLeeg(){
['eq-vraag','eq-uitleg','eq-o0','eq-o1','eq-o2','eq-o3'].forEach(id => {
var el = document.getElementById(id);
if(el) el.value = '';
});
var r = document.querySelector('input[name="eq-correct"]:checked');
if(r) r.checked = false;
var fEl = document.getElementById('eq-fout');
if(fEl) fEl.style.display = 'none';
}
function eigenVraagVerwijder(id){
var arr = eigenVragenLaad().filter(q => q.id !== id);
eigenVragenSla(arr);
eigenVragenToonLijst();
}
function eigenVragenToonLijst(){
var arr = eigenVragenLaad();
var lijstEl = document.getElementById('eq-lijst');
var aantalEl = document.getElementById('eq-aantal');
if(!lijstEl) return;
if(aantalEl) aantalEl.textContent = arr.length;
if(!arr.length){
lijstEl.innerHTML = '<div style="font-size:.82rem;color:#bbb;padding:.4rem 0">Nog geen vragen opgeslagen.</div>';
return;
}
lijstEl.innerHTML = arr.map(q =>
'<div style="background:#f8faff;border-radius:10px;padding:.65rem .9rem;display:flex;justify-content:space-between;align-items:flex-start;gap:.5rem">'
+'<div style="flex:1"><div style="font-size:.84rem;font-weight:600">'+ddEsc(q.q.substring(0,80))+(q.q.length>80?'…':'')+'</div>'
+'<div style="font-size:.74rem;color:#aaa;margin-top:.15rem">'+(q.typ==='mc'?'Meerkeuze':'Open vraag')+' · ⭐'.repeat(q.d||2)+'</div></div>'
+'<button onclick="eigenVraagVerwijder(\''+q.id+'\')" style="background:none;border:none;color:#e74c3c;cursor:pointer;font-size:.85rem;padding:0" title="Verwijder">🗑️</button>'
+'</div>'
).join('');
}
var _origGetData = null;
function koppelEigenVragen(){
if(_origGetData) return;
_origGetData = window.getData || null;
if(!_origGetData) return;
window.getData = function(){
var data = _origGetData.apply(this, arguments);
var eigen = eigenVragenLaad();
if(eigen.length && data && data.vr){
data = Object.assign({}, data, { vr: [...data.vr, ...eigen] });
}
return data;
};
}
setTimeout(koppelEigenVragen, 500);
