function lanceerConfetti(){
const kleuren=['#1a7a4a','#2ecc71','#f4a261','#e63946','#0369a1','#f59e0b'];
const canvas=document.createElement('canvas');
canvas.style.cssText='position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:9999';
document.body.appendChild(canvas);
const ctx=canvas.getContext('2d');
canvas.width=window.innerWidth; canvas.height=window.innerHeight;
const stukjes=Array.from({length:80},()=>({
x:Math.random()*canvas.width, y:-10,
r:Math.random()*6+3, c:kleuren[Math.floor(Math.random()*kleuren.length)],
vx:(Math.random()-.5)*4, vy:Math.random()*4+2,
rot:Math.random()*360, vrot:(Math.random()-.5)*8,
alpha:1, shape:Math.random()>.5?'rect':'circle'
}));
let frame=0;
function draw(){
ctx.clearRect(0,0,canvas.width,canvas.height);
stukjes.forEach(s=>{
ctx.save(); ctx.globalAlpha=s.alpha;
ctx.translate(s.x,s.y); ctx.rotate(s.rot*Math.PI/180);
ctx.fillStyle=s.c;
if(s.shape==='rect'){ctx.fillRect(-s.r,-s.r/2,s.r*2,s.r);}
else{ctx.beginPath();ctx.arc(0,0,s.r,0,Math.PI*2);ctx.fill();}
ctx.restore();
s.x+=s.vx; s.y+=s.vy; s.rot+=s.vrot; s.alpha-=.018;
});
frame++;
if(frame<80) requestAnimationFrame(draw);
else document.body.removeChild(canvas);
}
requestAnimationFrame(draw);
}
