function _decoderHash(niv,ow,goed,totaal){
const s=niv+ow+goed+totaal+'vla43';
let h=0;
for(let i=0;i<s.length;i++){h=(h*31+s.charCodeAt(i))&0xFFFFFFFF;}
return String(Math.abs(h)%9000+1000);
}
function decodeerKlascode(){
const code=(document.getElementById('decoder-input').value||'').trim().toUpperCase();
const res=document.getElementById('decoder-resultaat');
if(!code){res.innerHTML='<p style="color:#e74c3c;font-size:.85rem">Voer een code in.</p>';return;}
const d=code.split('-');
if(d.length!==4){res.innerHTML='<p style="color:#e74c3c;font-size:.85rem">Ongeldig formaat. Verwacht: NIVEAU-ONDERWERP-SCORE-HASH</p>';return;}
const [niv,ow,scoreStr,hashIn]=d;
const m=scoreStr.match(/^(\d+)V(\d+)$/);
if(!m){res.innerHTML='<p style="color:#e74c3c;font-size:.85rem">Ongeldige score (verwacht bijv. 8V10).</p>';return;}
const goed=parseInt(m[1]),totaal=parseInt(m[2]);
if(totaal===0||goed>totaal){res.innerHTML='<p style="color:#e74c3c;font-size:.85rem">Score klopt niet.</p>';return;}
const verwacht=_decoderHash(niv,ow,goed,totaal);
let geldig=(hashIn===verwacht);
if(!geldig){
try{const owMap={'MAR':'Markt','OW':'Overheid','ARB':'Arbeid','BL':'Buitenland','ENV':'Milieu'};
const owTxt=owMap[ow]||ow;
const nivMap={'TL':'TL','BB':'BB','K':'K','H':'HAVO','V':'VWO'};
const klassecode=genereerKlascode(goed,totaal,owTxt,nivMap[niv]||niv);
geldig=(klassecode.split('-')[3]===hashIn);}catch(e){}
}
const pct=Math.round((goed/totaal)*100);
const kleur=pct>=70?'#1a6b3a':pct>=50?'#e67e22':'#e74c3c';
const nL={BB:'VMBO Basis',K:'VMBO Kader',TL:'VMBO-TL',H:'HAVO',V:'VWO'};
const oL={MAR:'Markt & prijsvorming',OW:'Overheid',ARB:'Arbeid',BL:'Buitenland & EU',ENV:'Natuur & milieu',CON:'Consumenten & bankwezen',BEH:'Behoeften & schaarste',INT:'Internationale handel'};
res.innerHTML=`<div style="background:#fff;border-radius:12px;border:2px solid ${geldig?'#1a6b3a':'#e74c3c'};padding:1rem 1.2rem">
<div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.8rem">
<span style="font-size:1.3rem">${geldig?'\u2705':'\u26a0\ufe0f'}</span>
<strong style="color:${geldig?'#1a6b3a':'#e74c3c'};font-size:.95rem">${geldig?'Code geverifieerd':'Waarschuwing: code mogelijk aangepast'}</strong>
</div>
<table style="width:100%;border-collapse:collapse;font-size:.88rem">
<tr><td style="padding:.3rem .5rem;color:#888;width:130px">Niveau</td><td style="padding:.3rem .5rem;font-weight:700">${nL[niv]||niv}</td></tr>
<tr style="background:#f8f9fa"><td style="padding:.3rem .5rem;color:#888">Onderwerp</td><td style="padding:.3rem .5rem;font-weight:700">${oL[ow]||ow}</td></tr>
<tr><td style="padding:.3rem .5rem;color:#888">Score</td><td style="padding:.3rem .5rem"><strong style="font-size:1.1rem;color:${kleur}">${goed}/${totaal}</strong> <span style="color:${kleur};font-weight:700">(${pct}%)</span></td></tr>
<tr style="background:#f8f9fa"><td style="padding:.3rem .5rem;color:#888">Verificatie</td><td style="padding:.3rem .5rem;color:${geldig?'#1a6b3a':'#e74c3c'};font-weight:700">${geldig?'\u2713 Authentiek':'\u2717 Niet verifieerbaar'}</td></tr>
</table></div>`;
}
