html+='<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:.7rem;margin-bottom:1.2rem">';
html+=ddStatCard('📊 Totaal sessies',''+sessies,'escaperooms geslaagd','#1a5a8a');
html+=ddStatCard('❤️ Gem. levens over',gemLevens+' / 3','gemiddeld over alle escaperooms','#8e44ad');
