html+='<thead><tr style="background:#f0f0f0"><th style="padding:.45rem .6rem;font-size:.75rem;text-align:left;font-weight:700;color:#555">#</th><th style="text-align:left;padding:.45rem .6rem;font-size:.75rem;font-weight:700;color:#555">Vraag</th><th style="text-align:center;padding:.45rem .6rem;font-size:.75rem;font-weight:700;color:#555">% Fout</th></tr></thead>';
