function ddMcToggle(rid){
_ddMcRevealed[rid]=!_ddMcRevealed[rid];
ddMissionRender();
var el=document.getElementById('mc-body-'+rid);
if(el && _ddMcRevealed[rid]) setTimeout(function(){ el.scrollIntoView({behavior:'smooth',block:'nearest'}); },50);
}
