var _crScenarioIdx = 0;
var _crVolgorde = [];
var _crGeprobeerd = 0;
function crInit(){
var container = document.getElementById('cr-container');
if(!container) return;
var scenario = CR_SCENARIOS[_crScenarioIdx];
_crVolgorde = [];
_crGeprobeerd = 0;
var bank = scenario.keten.slice().sort(function(){ return Math.random() - 0.5; });
var html = '<div class="cr-wrap">';
html += '<div class="cr-titel">'+escHtml(scenario.titel)+'</div>';
html += '<div class="cr-scenario-titel">'+escHtml(scenario.beschrijving)+'</div>';
html += '<div style="display:flex;gap:.4rem;flex-wrap:wrap;margin-bottom:.9rem">';
CR_SCENARIOS.forEach(function(sc, idx){
var actief = idx === _crScenarioIdx ? 'style="background:var(--g);color:#fff;border-color:var(--g)"' : '';
html += '<button class="cr-btn sec" '+actief+' onclick="crKiesScenario('+idx+')" style="font-size:.75rem;padding:.3rem .7rem">'+escHtml(sc.titel.replace('Scenario: ',''))+'</button>';
});
html += '</div>';
html += '<div style="font-size:.8rem;font-weight:700;color:#555;margin-bottom:.3rem">🎯 Jouw keten (sleep hier de kaartjes naartoe):</div>';
html += '<div class="cr-keten" id="cr-keten" ondragover="crDragOver(event)" ondrop="crDrop(event,\'keten\')" ondragleave="crDragLeave(event)">';
html += '<span style="color:#bbb;font-size:.8rem;font-style:italic" id="cr-keten-placeholder">Sleep kaartjes hierheen in de juiste volgorde...</span>';
html += '</div>';
html += '<div style="font-size:.8rem;font-weight:700;color:#555;margin-bottom:.3rem;margin-top:.4rem">📦 Beschikbare kaartjes:</div>';
html += '<div class="cr-bank" id="cr-bank">';
bank.forEach(function(kaartje, idx){
html += '<span class="cr-kaartje" draggable="true" id="crk-'+idx+'" data-txt="'+encodeURIComponent(kaartje)+'"'
+ ' ondragstart="crDragStart(event)" onclick="crKlikKaartje(this)">'
+ '☰ '+escHtml(kaartje)+'</span>';
});
html += '</div>';
html += '<div class="cr-acties">';
html += '<button class="cr-btn" onclick="crControleer()">✅ Controleer volgorde</button>';
html += '<button class="cr-btn sec" onclick="crReset()">🔄 Opnieuw</button>';
html += '<button class="cr-btn sec" onclick="crToon()">💡 Toon juiste volgorde</button>';
html += '</div>';
html += '<div class="cr-feedback" id="cr-fb"></div>';
html += '<div id="cr-score-wrap" style="margin-top:.6rem;display:none">';
html += '<div class="cr-score" id="cr-score"></div>';
html += '</div>';
html += '</div>';
container.innerHTML = html;
crInitTouch();
}
function crKiesScenario(idx){
_crScenarioIdx = idx;
crInit();
}
var _crDragEl = null;
var _crDragFrom = null;
function crDragStart(e){
_crDragEl = e.currentTarget || e.target;
while(_crDragEl && !_crDragEl.classList.contains('cr-kaartje')) _crDragEl = _crDragEl.parentElement;
_crDragFrom = _crDragEl ? _crDragEl.parentElement.id : null;
e.dataTransfer.effectAllowed = 'move';
e.dataTransfer.setData('text/plain', _crDragEl ? _crDragEl.id : '');
var el = _crDragEl;
setTimeout(function(){ if(el) el.style.opacity = '0.4'; }, 0);
}
function crDragOver(e){
e.preventDefault();
e.dataTransfer.dropEffect = 'move';
var t = e.currentTarget;
t.classList.add('dragover');
}
function crDragLeave(e){
e.currentTarget.classList.remove('dragover');
}
function crDrop(e, zone){
e.preventDefault();
e.currentTarget.classList.remove('dragover');
if(!_crDragEl) return;
_crDragEl.style.opacity = '';
var placeholder = document.getElementById('cr-keten-placeholder');
if(placeholder) placeholder.remove();
if(zone === 'keten'){
document.getElementById('cr-keten').appendChild(_crDragEl);
} else {
document.getElementById('cr-bank').appendChild(_crDragEl);
}
_crDragEl = null;
}
var _crGekozen = null;
function crKlikKaartje(el){
if(!_crGekozen){
document.querySelectorAll('.cr-kaartje').forEach(function(k){ k.style.outline = ''; });
el.style.outline = '3px solid var(--g)';
_crGekozen = el;
} else if(_crGekozen === el){
el.style.outline = '';
_crGekozen = null;
} else {
var doelParent = el.parentElement;
var vanParent = _crGekozen.parentElement;
var placeholder = document.getElementById('cr-keten-placeholder');
if(placeholder && vanParent.id === 'cr-bank' && doelParent.id === 'cr-keten'){
placeholder.remove();
}
doelParent.insertBefore(_crGekozen, el);
_crGekozen.style.outline = '';
_crGekozen = null;
}
}
function crInitTouch(){
var keten = document.getElementById('cr-keten');
if(keten){
keten.addEventListener('click', function(e){
if(e.target === keten && _crGekozen){
var placeholder = document.getElementById('cr-keten-placeholder');
if(placeholder) placeholder.remove();
keten.appendChild(_crGekozen);
_crGekozen.style.outline = '';
_crGekozen = null;
}
});
}
}
function crControleer(){
var ketenEl = document.getElementById('cr-keten');
var kaartjes = ketenEl.querySelectorAll('.cr-kaartje');
var scenario = CR_SCENARIOS[_crScenarioIdx];
var juist = scenario.keten;
var fb = document.getElementById('cr-fb');
if(kaartjes.length === 0){
fb.className = 'cr-feedback show fout';
fb.innerHTML = '⚠️ Sleep eerst de kaartjes naar de keten!';
return;
}
if(kaartjes.length < juist.length){
fb.className = 'cr-feedback show fout';
fb.innerHTML = '⚠️ Je hebt nog niet alle kaartjes in de keten geplaatst. Er missen er nog '+( juist.length - kaartjes.length)+'.';
return;
}
_crGeprobeerd++;
var aantalGoed = 0;
var kaartjesArr = Array.from(kaartjes);
kaartjesArr.forEach(function(k, idx){
var txt = decodeURIComponent(k.dataset.txt || '');
k.classList.remove('cr-goed','cr-fout');
if(idx < juist.length && txt === juist[idx]){
k.classList.add('cr-goed');
k.innerHTML = '✓ ' + escHtml(txt);
aantalGoed++;
} else {
k.classList.add('cr-fout');
k.innerHTML = '✗ ' + escHtml(txt);
}
});
if(aantalGoed === juist.length){
fb.className = 'cr-feedback show goed';
fb.innerHTML = '🎉 <strong>Geweldig!</strong> Je hebt de economische kettingreactie helemaal goed! Je begrijpt hoe oorzaken leiden tot gevolgen in de economie.';
crRegistreerAnalytics(scenario.id, true, _crGeprobeerd);
document.getElementById('cr-score-wrap').style.display = '';
document.getElementById('cr-score').textContent = _crGeprobeerd === 1 ? '⭐ Perfect in 1 poging!' : '✅ Gelukt in ' + _crGeprobeerd + ' pogingen';
} else {
fb.className = 'cr-feedback show fout';
fb.innerHTML = '❌ <strong>' + aantalGoed + ' van de ' + juist.length + ' kaartjes staan op de juiste plek.</strong> De rode kaartjes staan fout. Probeer het opnieuw!';
crRegistreerAnalytics(scenario.id, false, _crGeprobeerd);
}
}
function crToon(){
var scenario = CR_SCENARIOS[_crScenarioIdx];
var fb = document.getElementById('cr-fb');
fb.className = 'cr-feedback show goed';
fb.innerHTML = '<strong>💡 Juiste volgorde:</strong><br>'
+ scenario.keten.map(function(k, i){
return '<span style="display:inline-block;background:#d8f0e8;border:1px solid #a8d8a8;border-radius:6px;padding:.2rem .55rem;margin:.2rem;font-size:.8rem">'
+ (i+1)+'. '+escHtml(k)+'</span>'
+ (i < scenario.keten.length - 1 ? ' <span style="color:#888">→</span>' : '');
}).join(' ');
crRegistreerAnalytics(scenario.id, false, _crGeprobeerd + 1);
}
function crReset(){
crInit();
}
function crRegistreerAnalytics(scenarioId, succes, pogingen){
try{
var da = JSON.parse(localStorage.getItem('docent_analytics')||'{}');
if(!da.causaal) da.causaal = {};
if(!da.causaal[scenarioId]) da.causaal[scenarioId] = {naam: scenarioId, pogingen:[], successen:0, totaal:0};
da.causaal[scenarioId].totaal++;
da.causaal[scenarioId].pogingen.push(pogingen);
if(succes) da.causaal[scenarioId].successen++;
if(da.causaal[scenarioId].pogingen.length > 50) da.causaal[scenarioId].pogingen.shift();
localStorage.setItem('docent_analytics', JSON.stringify(da));
}catch(e){}
}
function escHtml(s){
return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
(function(){
var origGo = window.go;
window.go = function(modus){
if(modus === 'cr'){
document.querySelectorAll('.screen').forEach(function(s){ s.classList.remove('active'); });
var s = document.getElementById('s-cr');
if(s){ s.classList.add('active'); crInit(); }
return;
}
if(typeof origGo === 'function') origGo(modus);
};
})();
var _foutTracker = (function(){
try{ return JSON.parse(localStorage.getItem('ft_fouten')||'{}'); }catch(e){ return {}; }
})();
