var prHuidigeRubric = null;
var prScores = {};
function prKiesRubric(id){
document.querySelectorAll('.pr-rubric-btn').forEach(function(b){ b.classList.remove('actief'); });
var btn = document.querySelector('[data-id="'+id+'"]');
if(btn) btn.classList.add('actief');
prHuidigeRubric = PR_RUBRICS[id];
var naamEl = document.getElementById('pr-rubric-naam');
naamEl.textContent = '✓ Geselecteerd: ' + prHuidigeRubric.naam;
naamEl.style.display = '';
document.getElementById('pr-start-btn').style.display = '';
}
function prStartBeoordeling(){
var tekst = (document.getElementById('pr-tekst').value||'').trim();
if(!tekst){ alert('Plak eerst de tekst van de medeleerling in.'); return; }
if(!prHuidigeRubric){ alert('Kies eerst een rubric.'); return; }
prScores = {};
var wrap = document.getElementById('pr-criteria-wrap');
wrap.innerHTML = prHuidigeRubric.criteria.map(function(cr){
return '<div class="pr-criterium" id="pr-cr-'+cr.id+'">'
+'<div class="pr-criterium-label">'+ddEsc(cr.label)+'</div>'
+'<div class="pr-scores">'
+cr.scores.map(function(s, i){
return '<button class="pr-score-btn" onclick="prSelectScore(\''+cr.id+'\','+i+',this)">'+ddEsc(s)+'</button>';
}).join('')
+'</div></div>';
}).join('');
document.getElementById('pr-stap1').style.display = 'none';
document.getElementById('pr-stap2').style.display = '';
}
function prSelectScore(criteriumId, score, btn){
prScores[criteriumId] = score;
var wrap = btn.closest('.pr-scores');
Array.from(wrap.children).forEach(function(b){ b.classList.remove('geselecteerd'); });
btn.classList.add('geselecteerd');
}
function prGenereerFeedback(){
if(!prHuidigeRubric) return;
var cr = prHuidigeRubric.criteria;
var missend = cr.filter(function(c){ return prScores[c.id] === undefined; });
if(missend.length){ alert('Beoordeel nog alle criteria ('+missend.length+' ontbreken).'); return; }
var maxScore = cr.length * (Math.max.apply(null, cr[0].scores.map(function(_,i){ return i; })));
var totaalMax = cr.reduce(function(sum, c){ return sum + (c.scores.length - 1); }, 0);
var behaald = cr.reduce(function(sum, c){ return sum + (prScores[c.id]||0); }, 0);
var pct = Math.round((behaald/totaalMax)*100);
var tip = (document.getElementById('pr-tip').value||'').trim();
var kleur = pct >= 75 ? '#27ae60' : pct >= 50 ? '#e67e22' : '#c0392b';
var oordeel = pct >= 75 ? '✅ Goed werk' : pct >= 50 ? '⚠️ Voldoende, maar kan beter' : '❌ Needs improvement';
var html = '<div style="text-align:center;padding:.8rem 0 1.2rem">'
+'<div style="font-size:2.5rem;font-weight:800;color:'+kleur+'">'+behaald+'/'+totaalMax+'</div>'
+'<div style="font-size:1rem;font-weight:700;color:'+kleur+'">'+oordeel+'</div>'
+'<div style="font-size:.82rem;color:#aaa;margin-top:.2rem">('+pct+'%)</div></div>';
html += '<table style="width:100%;border-collapse:collapse;font-size:.84rem;margin-bottom:1rem">';
html += '<thead><tr style="background:#f5f5f5"><th style="padding:.5rem .7rem;text-align:left">Criterium</th><th style="padding:.5rem .7rem;text-align:center">Score</th><th style="padding:.5rem .7rem;text-align:left">Beoordeling</th></tr></thead><tbody>';
cr.forEach(function(c){
var sc = prScores[c.id]||0;
var max = c.scores.length - 1;
var kl = sc === max ? '#27ae60' : sc > 0 ? '#e67e22' : '#c0392b';
html += '<tr><td style="padding:.45rem .7rem;border-bottom:1px solid #f0f0f0">'+ddEsc(c.label)+'</td>'
+'<td style="padding:.45rem .7rem;border-bottom:1px solid #f0f0f0;text-align:center;font-weight:700;color:'+kl+'">'+sc+'/'+max+'</td>'
+'<td style="padding:.45rem .7rem;border-bottom:1px solid #f0f0f0;font-size:.78rem;color:#666">'+ddEsc(c.scores[sc].replace(/^\d+ [–-] /,''))+'</td></tr>';
});
html += '</tbody></table>';
if(tip){
html += '<div style="background:#fff7ed;border-radius:8px;padding:.7rem .9rem;border-left:3px solid #f59e0b">'
+'<div style="font-weight:700;font-size:.82rem;color:#92400e;margin-bottom:.2rem">💬 Verbeterpunt</div>'
+'<div style="font-size:.85rem;color:#78350f">'+ddEsc(tip)+'</div></div>';
}
document.getElementById('pr-resultaat-body').innerHTML = html;
document.getElementById('pr-stap2').style.display = 'none';
document.getElementById('pr-resultaat').style.display = '';
}
