function toggleBegrippenMenu(e) {
e.stopPropagation();
const menu = document.getElementById('begrippen-submenu');
const pijl = document.getElementById('begrippen-pijl');
const wrap = document.getElementById('begrippen-wrap');
if (!menu) return;
const open = menu.style.display === 'block';
menu.style.display = open ? 'none' : 'block';
if (pijl) pijl.style.transform = open ? 'rotate(0deg)' : 'rotate(180deg)';
if (wrap) wrap.setAttribute('aria-expanded', String(!open));
}
document.addEventListener('click', function(e) {
const menu = document.getElementById('begrippen-submenu');
const wrap = document.getElementById('begrippen-wrap');
if (menu && menu.style.display === 'block' && wrap && !wrap.contains(e.target)) {
menu.style.display = 'none';
const pijl = document.getElementById('begrippen-pijl');
if (pijl) pijl.style.transform = 'rotate(0deg)';
wrap.setAttribute('aria-expanded', 'false');
}
});
const NIEUWS_RSS_URL = 'https://api.rss2json.com/v1/api.json?rss_url=https%3A%2F%2Ffeeds.nos.nl%2Fnosnieuwseconomie';
const NIEUWS_MAX     = 8;
const NIEUWS_FALLBACK = [
{ title: 'Economie draait op volle toeren — werkloosheid op historisch laag niveau', url: 'https://www.nos.nl/economie' },
{ title: 'ECB bewaakt inflatiedoelstelling van 2% — rente blijft bepalend thema', url: 'https://www.nos.nl/economie' },
{ title: 'Overheidsfinanciën onder druk: begrotingstekort en staatsschuld in debat', url: 'https://www.nos.nl/economie' },
];
async function laadNieuwsTicker() {
const track = document.getElementById('nieuws-track');
if (!track) return;
let items = [];
try {
const resp = await fetch(NIEUWS_RSS_URL);
if (resp.ok) {
const data = await resp.json();
if (data.status === 'ok' && Array.isArray(data.items) && data.items.length > 0) {
items = data.items
.slice(0, NIEUWS_MAX)
.map(item => ({
title: item.title.trim(),
url:   item.link || 'https://www.nos.nl/economie'
}));
}
}
} catch (e) {
}
if (items.length === 0) items = NIEUWS_FALLBACK;
const maakItems = () => items.map(item =>
`<a href="${ddEsc(item.url)}" target="_blank" rel="noopener noreferrer">${ddEsc(item.title)}</a><span class="sep">◆</span>`
).join('');
track.innerHTML = maakItems() + maakItems();
const totaalTekens = items.reduce((s, i) => s + i.title.length, 0);
const duur = Math.max(30, Math.round(totaalTekens * 0.28));
track.style.animationDuration = duur + 's';
const label = document.getElementById('nieuws-label');
if (label) {
const nu    = new Date();
const datum = nu.toLocaleDateString('nl-NL', { weekday: 'short', day: 'numeric', month: 'short' });
label.innerHTML = `📰 Nieuws <span style="font-weight:400;opacity:.7;margin-left:4px">${datum}</span>`;
}
}
document.addEventListener('DOMContentLoaded', () => {
laadNieuwsTicker();
setInterval(laadNieuwsTicker, 60 * 60 * 1000);
});
