window.rtAnalyseerFout = (ingevoerd, juist, context = '') => {
if (isNaN(ingevoerd) || isNaN(juist)) return null;
const ctx = context.toLowerCase();
const isProcentVraag =
ctx.includes('procent') || ctx.includes('%') ||
ctx.includes('inflatie') || ctx.includes('verandering') ||
ctx.includes('stijging') || ctx.includes('daling') ||
ctx.includes('mutatie');
if (!isProcentVraag) return null;
const tol = Math.abs(juist) * 0.02 + 0.01;
if (Math.abs(ingevoerd * 100 - juist) < tol) {
return `
<strong>💡 Bijna!</strong> Je antwoord lijkt een factor 100 te klein.
Heb je het als decimaal getal ingevuld in plaats van als percentage?
<br>Tip: als je 0,05 uitrekent maar het antwoord in <em>procenten</em>
moet zijn, vermenigvuldig je met 100 → <strong>${juist}</strong>%.
<br><small>Formule: procentuele verandering = (nieuw − oud) ÷ oud × 100%</small>
`;
}
if (Math.abs(ingevoerd / 100 - juist) < tol) {
return `
<strong>💡 Let op!</strong> Je antwoord is een factor 100 te groot.
Vergeet je het "<em>× 100%</em>" als omrekenstap toe te passen?
<br>Tip: deel je uitkomst nog door 100, of zet het resultaat om van
decimaal naar procent: ${(juist / 100).toFixed(4)} × 100 = <strong>${juist}</strong>%.
<br><small>Formule: procentuele verandering = (nieuw − oud) ÷ oud × 100%</small>
`;
}
if (Math.abs(juist) > 0.01) {
const ratio = ingevoerd / juist;
const rondeGetallen = [5, 10, 15, 20, 25, 50, 100, 200, 500, 1000];
const isRond = rondeGetallen.some(r => Math.abs(ratio - r) < 0.15 * r);
if (isRond && Math.abs(ingevoerd) > Math.abs(juist) * 5) {
return `
<strong>💡 Tussenstap gemist?</strong> Je antwoord is veel groter dan verwacht.
Bij <em>procentuele verandering</em> moet je het verschil
(nieuw − oud) <strong>delen door de oude waarde</strong>.
<br>Formule: (nieuw − oud) ÷ <em>oud</em> × 100%
<br><small>Controleer of je die deelstap hebt gemaakt.</small>
`;
}
}
return null;
};
