window.bpCoachHint = (verschil, posten, placings) => {
const fmt = n => '€' + Math.abs(n).toLocaleString('nl-NL');
const abs = Math.abs(verschil);
const kandidaten = posten.filter(p => placings[p.id] !== null);
const dichtstbij = kandidaten.sort((a, b) =>
Math.abs(a.bedrag - abs) - Math.abs(b.bedrag - abs)
)[0];
let postHint = '';
if (dichtstbij && Math.abs(dichtstbij.bedrag - abs) / abs < 0.15) {
postHint = ` Controleer specifiek de post <strong>${dichtstbij.naam}</strong>
(${fmt(dichtstbij.bedrag)}) — staat die aan de juiste kant?`;
}
if (verschil > 0) {
return `
Je Debet-kant is <strong>${fmt(verschil)}</strong> te hoog.
Misschien staat er een post aan de linkerkant die eigenlijk
bij <em>Credit (financiering/passiva)</em> hoort.${postHint}
<br><small>Onthoud: <em>bezittingen</em> → Debet | <em>schulden &amp; eigen vermogen</em> → Credit</small>
`;
}
if (verschil < 0) {
return `
Je Credit-kant is <strong>${fmt(verschil)}</strong> te hoog.
Heb je misschien een <em>bezitting</em> (activa) per ongeluk
bij Credit geplaatst?${postHint}
<br><small>Onthoud: <em>bezittingen</em> → Debet | <em>schulden &amp; eigen vermogen</em> → Credit</small>
`;
}
return '';
};
